/**
 * @summary Get wallet on-chain transactions
 */
export const getGetWalletTransactionsUrl = (
  params: GetWalletTransactionsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/wallet/transactions?${stringifiedParams}`
    : `/api/wallet/transactions`;
};

export const getWalletTransactions = async (
  params: GetWalletTransactionsParams,
  options?: RequestInit,
): Promise<WalletTransaction[]> => {
  return customFetch<WalletTransaction[]>(getGetWalletTransactionsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetWalletTransactionsQueryKey = (
  params?: GetWalletTransactionsParams,
) => {
  return [`/api/wallet/transactions`, ...(params ? [params] : [])] as const;
};

export const getGetWalletTransactionsQueryOptions = <
  TData = Awaited<ReturnType<typeof getWalletTransactions>>,
  TError = ErrorType<unknown>,
>(
  params: GetWalletTransactionsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getWalletTransactions>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetWalletTransactionsQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getWalletTransactions>>
  > = ({ signal }) =>
    getWalletTransactions(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getWalletTransactions>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetWalletTransactionsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getWalletTransactions>>
>;
export type GetWalletTransactionsQueryError = ErrorType<unknown>;

